class Solution:
    def canPartitionKSubsets(self, nums, k):
        total = sum(nums)
        if total % k != 0:
            return False
        target = total // k
        if any(x > target for x in nums):
            return False
        n = len(nums)
        used = [False] * n
        nums_sorted = sorted(nums, reverse=True)
        def backtrack(groups_done, cur_sum, start):
            if groups_done == k:
                return True
            if cur_sum == target:
                return backtrack(groups_done + 1, 0, 0)
            for i in range(start, n):
                if not used[i] and cur_sum + nums_sorted[i] <= target:
                    used[i] = True
                    if backtrack(groups_done, cur_sum + nums_sorted[i], i + 1):
                        return True
                    used[i] = False
            return False
        return backtrack(0, 0, 0)

